```go
package counter

import (
    "cosmossdk.io/depinject"
    sdk "github.com/cosmos/cosmos-sdk/types"
    "github.com/cosmos/cosmos-sdk/types/module"
)

var (
    _ module.AppModule = AppModule{}
)

type AppModule struct {
   keeper Keeper
}

func NewAppModule(keeper Keeper) AppModule {
    return AppModule{
        keeper: keeper,
    }
}

// RegisterInvariants does nothing for now.
func (am AppModule) RegisterInvariants(ir sdk.InvariantRegistry) {}

// Route returns the message routing key for the module.
func (am AppModule) Route() sdk.Route { return sdk.NewRoute(RouterKey, NewHandler(am.keeper)) }

// QuerierRoute returns the querier route name.
func (am AppModule) QuerierRoute() string { return ModuleName }

// LegacyQuerierHandler returns the legacy querier handler.
func (am AppModule) LegacyQuerierHandler(_ *sdk.LegacyAmino) sdk.Querier { return nil }

// RegisterServices registers a gRPC query service on the provided server.
func (am AppModule) RegisterServices(cfg module.Configurator) {
    RegisterMsgServer(cfg.MsgServer(), NewMsgServerImpl(am.keeper))
}

// InitGenesis initializes the module's state from a provided genesis state.
func (am AppModule) InitGenesis(ctx sdk.Context, cdc codec.JSONCodec, gs json.RawMessage) []abci.ValidatorUpdate {
    var genState GenesisState
    cdc.MustUnmarshalJSON(gs, &genState)
    return InitGenesis(ctx, am.keeper, &genState)
}

// ExportGenesis returns the module's exported genesis state as raw JSON bytes.
func (am AppModule) ExportGenesis(ctx sdk.Context, cdc codec.JSONCodec) json.RawMessage {
    genState := ExportGenesis(ctx, am.keeper)
    return cdc.MustMarshalJSON(genState)
}

// ConsensusVersion implements AppModule/ConsensusVersion.
func (AppModule) ConsensusVersion() uint64 { return 1 }

// InitModule sets up the keeper and initializes any necessary dependencies.
func InitModule(
    kvStoreService store.KVStoreService,
    cdc codec.Codec,
    schema service.Schema,
) AppModule {
    kvStore := kvStoreService.OpenKVStore("counter")
    counterMap, err := collections.NewMap(schema, kvStore, "counters", []byteCodec{}, uint64Codec{})
    if err != nil {
        panic(err)
    }

    keeper := Keeper{
        cdc:      cdc,
        counters: counterMap,
    }

    return NewAppModule(keeper)
}

func init() {
    depinject.Register(
        func(kvStoreService store.KVStoreService, cdc codec.Codec, schema service.Schema) AppModule {
            return InitModule(kvStoreService, cdc, schema)
        },
    )
}
```

