This file contains the Keeper with collections.Map for storing counters.

```go
package keeper

import (
    "context"

    "cosmossdk.io/collections"
    sdk "github.com/cosmos/cosmos-sdk/types"
)

type Keeper struct {
    cdc      codec.Codec
    counters *collections.Map[collections.Bytes, uint64]
}

func (k Keeper) GetCounter(ctx context.Context, addr sdk.AccAddress) (uint64, error) {
    return k.counters.Get(ctx, collections.NewPrefixedBytes([]byte(QueryPrefixCounter), addr))
}

func (k Keeper) SetCounter(ctx context.Context, addr sdk.AccAddress, value uint64) error {
    return k.counters.Set(ctx, collections.NewPrefixedBytes([]byte(QueryPrefixCounter), addr), value)
}
