This file contains the MsgServer with Increment and Reset messages.

```go
package keeper

import (
    sdk "github.com/cosmos/cosmos-sdk/types"
    sdkerrors "github.com/cosmos/cosmos-sdk/types/errors"

    "example/x/counter/types"
)

type msgServer struct {
    Keeper
}

var _ types.MsgServer = &msgServer{}

func NewMsgServerImpl(k Keeper) *msgServer {
    return &msgServer{k}
}

// Increment increments the counter for an address.
func (ms msgServer) Increment(goCtx context.Context, msg *types.MsgIncrement) (*types.MsgIncrementResponse, error) {
    ctx := sdk.UnwrapSDKContext(goCtx)
    currentCount, err := ms.GetCounter(ctx.Context(), msg.Address)
    if err != nil && !collections.IsNotFound(err) {
        return nil, err
    }

    newCount := currentCount + 1
    if err := ms.SetCounter(ctx.Context(), msg.Address, newCount); err != nil {
        return nil, sdkerrors.Wrapf(sdkerrors.ErrInvalidRequest, "failed to set counter: %s", err.Error())
    }

    return &types.MsgIncrementResponse{}, nil
}

// Reset resets the counter for an address.
func (ms msgServer) Reset(goCtx context.Context, msg *types.MsgReset) (*types.MsgResetResponse, error) {
    ctx := sdk.UnwrapSDKContext(goCtx)
    if err := ms.SetCounter(ctx.Context(), msg.Address, 0); err != nil {
        return nil, sdkerrors.Wrapf(sdkerrors.ErrInvalidRequest, "failed to reset counter: %s", err.Error())
    }

    return &types.MsgResetResponse{}, nil
}
