### 7. `genesis.go`
This file handles the module's genesis state.

```go
package counter

import (
    "context"
    "encoding/json"

    sdk "github.com/cosmos/cosmos-sdk/types"
)

type GenesisState struct {
    Counters []Counter `json:"counters"`
}

type Counter struct {
    Address sdk.AccAddress `json:"address"`
    Value   uint64         `json:"value"`
}

func NewGenesisState(counters ...Counter) *GenesisState {
    return &GenesisState{Counters: counters}
}

// DefaultGenesis returns a default genesis state
func DefaultGenesis() *GenesisState {
    return NewGenesisState()
}

// InitGenesis initializes the module's state from a provided genesis state.
func InitGenesis(ctx sdk.Context, k Keeper, genState *GenesisState) []abci.ValidatorUpdate {
    for _, counter := range genState.Counters {
        if err := k.SetCounter(ctx.Context(), counter.Address, counter.Value); err != nil {
            panic(err)
        }
    }

    return []abci.ValidatorUpdate{}
}

// ExportGenesis returns the module's exported genesis state as raw JSON bytes.
func ExportGenesis(ctx sdk.Context, k Keeper) *GenesisState {
    counters := make([]Counter, 0)

    err := k.counters.Walk(ctx.Context(), func(key collections.Bytes, value uint64) error {
        addr := sdk.AccAddress(key[8:])
        counters = append(counters, Counter{Address: addr, Value: value})
        return nil
    })
    if err != nil {
        panic(err)
    }

    return &GenesisState{
        Counters: counters,
    }
}
```

