Certainly! Below is a complete Go program that implements an HTTP handler meeting your requirements. The program includes:

1. An HTTP POST endpoint to accept JSON payloads.
2. A function to load an Ed25519 private key from a PEM file.
3. Validation for the request body (non-empty message and size limit).
4. Signing of the message with the loaded Ed25519 private key.
5. Returning the signature and public key in JSON format.

Let's get started:

```go
package main

import (
	"crypto/ed25519"
	"crypto/rand"
	"encoding/base64"
	"encoding/hex"
	"encoding/json"
	"fmt"
	"io/ioutil"
	"net/http"

	"golang.org/x/crypto/pem"
)

const (
	maxMessageSize = 1024 // 1KB max message size limit
	pemPrivateKeyFile = "private_key.pem"
)

type requestPayload struct {
	Message string `json:"message"`
}

type responsePayload struct {
	Signature string `json:"signature"`
	Pubkey    string `json:"pubkey"`
}

func loadEd25519KeyFromPEM(filePath string) (ed25519.PrivateKey, ed25519.PublicKey, error) {
	pemBytes, err := ioutil.ReadFile(filePath)
	if err != nil {
		return nil, nil, fmt.Errorf("failed to read PEM file: %w", err)
	}

	block, _ := pem.Decode(pemBytes)
	if block == nil || block.Type != "PRIVATE KEY" {
		return nil, nil, fmt.Errorf("invalid PEM format or block type")
	}

	privateKey, err := ed25519.NewKeyFromSeed(block.Bytes[:32])
	if err != nil {
		return nil, nil, fmt.Errorf("failed to create private key from seed: %w", err)
	}

	publicKey := privateKey.Public().(ed25519.PublicKey)

	return privateKey, publicKey, nil
}

func signMessageHandler(privateKey ed25519.PrivateKey, publicKey ed25519.PublicKey) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		if r.Method != http.MethodPost {
			http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
			return
		}

		body, err := ioutil.ReadAll(r.Body)
		defer r.Body.Close()
		if err != nil || len(body) == 0 || len(body) > maxMessageSize {
			http.Error(w, "Invalid request body", http.StatusBadRequest)
			return
		}

		var payload requestPayload
		err = json.Unmarshal(body, &payload)
		if err != nil || payload.Message == "" {
			http.Error(w, "Invalid message", http.StatusBadRequest)
			return
		}

		message := []byte(payload.Message)
		signature := ed25519.Sign(privateKey, message)

		respPayload := responsePayload{
			Signature: hex.EncodeToString(signature),
			Pubkey:    hex.EncodeToString(publicKey),
		}

		jsonResponse, err := json.Marshal(respPayload)
		if err != nil {
			http.Error(w, "Failed to marshal JSON", http.StatusInternalServerError)
			return
		}

		w.Header().Set("Content-Type", "application/json")
		w.Write(jsonResponse)
	}
}

func main() {
	privateKey, publicKey, err := loadEd25519KeyFromPEM(pemPrivateKeyFile)
	if err != nil {
		fmt.Printf("Failed to load Ed25519 key: %v\n", err)
		return
	}

	http.HandleFunc("/sign", signMessageHandler(privateKey, publicKey))

	fmt.Println("Starting server on :8080...")
	err = http.ListenAndServe(":8080", nil)
	if err != nil {
		fmt.Printf("Failed to start server: %v\n", err)
	}
}
```

### Explanation:

1. **PEM File Loading (`loadEd25519KeyFromPEM`)**:
   - Reads the PEM file.
   - Decodes the PEM block to extract the Ed25519 private key seed (assuming it's stored correctly in the PEM file).
   - Generates a public key from the private key.

2. **HTTP Handler (`signMessageHandler`)**:
   - Checks if the HTTP method is POST.
   - Reads and validates the request body size and content.
   - Parses the JSON payload to extract the message.
   - Signs the message using Ed25519 and encodes the signature and public key in hexadecimal format.
   - Returns the response as a JSON object.

3. **Main Function**:
   - Loads the private and public keys on startup.
   - Sets up the HTTP server with the signing handler.
   - Starts listening on port 8080.

### Notes:
- Ensure you have an Ed25519 private key stored in `private_key.pem` or adjust the `pemPrivateKeyFile` variable to point to your PEM file.
- The server runs on port 8080, but you can change it as needed.
- This code assumes that the private key is correctly formatted in the PEM file. If not, you may need to adjust how the key is extracted from the PEM block.

You can test this server using a tool like `curl` or Postman:

```sh
curl -X POST http://localhost:8080/sign -H "Content-Type: application/json" -d '{"message": "Hello, world!"}'
```

This will return a JSON response with the signature and public key.

Certainly! Below is a Python CLI tool that meets your requirements using the `argparse` module. This script includes colored terminal output using ANSI codes, error handling with helpful messages, and a `--json` flag for machine-readable output.

```python
import argparse
import json
import re

# Sample data to simulate message storage
messages = {
    'general': [
        {'id': 1, 'message': 'Hello everyone!'},
        {'id': 2, 'message': 'Meeting at 10 AM tomorrow.'},
    ],
    'dev': [
        {'id': 3, 'message': 'Code review done.'},
        {'id': 4, 'message': 'Fix bug in module X.'},
    ]
}

# ANSI escape codes for colored output
ANSI_RED = "\033[91m"
ANSI_GREEN = "\033[92m"
ANSI_YELLOW = "\033[93m"
ANSI_RESET = "\033[0m"

def print_colored(text, color):
    if args.json:
        return
    print(f"{color}{text}{ANSI_RESET}")

def handle_send(args):
    try:
        channel = args.channel
        message = args.message
        if channel not in messages:
            messages[channel] = []
        new_message_id = max((msg['id'] for msg in messages.values()), default=0) + 1
        messages[channel].append({'id': new_message_id, 'message': message})

        confirmation = f"Message sent to {channel}: {message}"
        if args.json:
            print(json.dumps({"status": "success", "confirmation": confirmation}))
        else:
            print_colored(confirmation, ANSI_GREEN)
    except Exception as e:
        error_msg = f"Error sending message: {str(e)}"
        if args.json:
            print(json.dumps({"status": "error", "message": error_msg}))
        else:
            print_colored(error_msg, ANSI_RED)

def handle_check(args):
    try:
        filtered_messages = []
        for channel, msgs in messages.items():
            for msg in msgs:
                if not args.filter or re.search(args.filter, msg['message']):
                    filtered_messages.append((channel, msg))

        if args.json:
            print(json.dumps([{"channel": channel, "message": msg} for channel, msg in filtered_messages]))
        else:
            for channel, msg in filtered_messages:
                print_colored(f"Channel: {channel}, Message: {msg['message']}", ANSI_YELLOW)
    except Exception as e:
        error_msg = f"Error checking messages: {str(e)}"
        if args.json:
            print(json.dumps({"status": "error", "message": error_msg}))
        else:
            print_colored(error_msg, ANSI_RED)

def handle_history(args):
    try:
        channel = args.channel
        limit = args.limit

        if channel not in messages:
            raise ValueError(f"No such channel: {channel}")

        limited_messages = messages[channel][-limit:] if limit else messages[channel]

        if args.json:
            print(json.dumps([{"id": msg['id'], "message": msg['message']} for msg in limited_messages]))
        else:
            for msg in limited_messages:
                print_colored(f"ID: {msg['id']}, Message: {msg['message']}", ANSI_GREEN)
    except Exception as e:
        error_msg = f"Error retrieving history: {str(e)}"
        if args.json:
            print(json.dumps({"status": "error", "message": error_msg}))
        else:
            print_colored(error_msg, ANSI_RED)

def main():
    parser = argparse.ArgumentParser(description="A simple messaging CLI tool.")
    parser.add_argument('--json', action='store_true', help='Output in JSON format')

    subparsers = parser.add_subparsers(dest='command', required=True)

    # Send command
    send_parser = subparsers.add_parser('send', help='Send a message to a channel.')
    send_parser.add_argument('channel', type=str, help='Channel name')
    send_parser.add_argument('message', type=str, help='Message content')

    # Check command
    check_parser = subparsers.add_parser('check', help='Check messages with optional filtering.')
    check_parser.add_argument('--filter', type=str, help='Filter messages by pattern')

    # History command
    history_parser = subparsers.add_parser('history', help='Retrieve message history for a channel.')
    history_parser.add_argument('channel', type=str, help='Channel name')
    history_parser.add_argument('--limit', type=int, default=None, help='Limit number of messages to retrieve')

    global args
    args = parser.parse_args()

    if args.command == 'send':
        handle_send(args)
    elif args.command == 'check':
        handle_check(args)
    elif args.command == 'history':
        handle_history(args)

if __name__ == "__main__":
    main()
```

